head.script:
scwin.count2 = 0;
scwin.count3 = 0;
scwin.clsCd = 0;
scwin.imptotal = 0;
scwin.exptotal = 0;

//-------------------------------------------------------------------------
// 온로드시 
//-------------------------------------------------------------------------    
scwin.onpageload = async function () {
    scwin.f_initDivHoldEachWorkPlanList();
    scwin.f_initCarryingVesselCompletionInformation();

    dma_sellingItemCondition.set("sellItemCd1", "03");
    dma_sellingItemCondition.set("sellItemCd2", "0172");
    dma_sellingItemCondition.set("sellItemCd3", "0177");
    await $c.sbm.execute(sbm_sellingItemCondition);

    dma_conditionContract.set("cvsslMgntNo", "");
    dma_conditionContract.set("wrkStpCd", "");
    dma_conditionContract.set("odrKndCd", "");

    ed_cvsslMgntNo.focus();
};

scwin.onUdcCompleted = function () {
    $c.gus.cfDisableBtn([btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);
}

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_RetrieveShiftingResults();
};

scwin.btn_PopUp_onclick = function (e) {
    scwin.f_openPopUp();
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_Caculate_onclick = function (e) {
    scwin.f_Caculate();
};

scwin.btn_AddShift_onclick = function (e) {
    scwin.f_AddRowShift();
};

scwin.btn_DeleteShift_onclick = function (e) {
    scwin.f_DeleteRowShift();
};

scwin.btn_CancelShift_onclick = function (e) {
    let nRow = ds_cargoShiftingResults.getRowPosition();
    if (ds_cargoShiftingResults.getRowStatus(nRow) === "C") {
        // 신규추가행
        ds_cargoShiftingResults.removeRow(nRow);
    }
    else {
        ds_cargoShiftingResults.undoRow(nRow);
    }
};

scwin.f_RetrieveShiftingResults = async function () {
    // 검색조건 필수 입력 체크
    if (!(await $c.gus.cfValidate([ed_cvsslMgntNo]))) return;

    dma_condition.setJSON({});
    // 본선관리번호
    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    await $c.sbm.execute(sbm_condition);
};

//-------------------------------------------------------------------------
// 본선작업계획상세조회 테이블 생성
//-------------------------------------------------------------------------
scwin.f_DivHoldEachWorkPlanList = function () {
    ds_carryingVesselBasisInfo.setRowPosition(0);

    var hasData = ds_carryingVesselBasisInfo.getRowCount() > 0;

    // 데이터가 없으면 기본 UI로 초기화 후 종료
    if (!hasData) {
        scwin.f_initDivHoldEachWorkPlanList();
        return;
    }

    var d = {};
    // 문자열 필드 일괄 추출
    var fields = ["vsslNm", "lineNm", "shpCoNm", "impPortcnt", "expPortcnt",
        "impRepKcg", "expRepKcg", "wrkPlNm", "cfmanNm", "cvsslFmanCnt", "groundFmanCnt"];

    fields.forEach(function (field) {
        d[field] = ds_carryingVesselBasisInfo.getCellData(0, field);
    });

    // 날짜 필드 포맷 처리 (####/##/## ##:## 형식)
    ["arrvlportDtm", "deprtportDtm"].forEach(function (field) {
        var val = ds_carryingVesselBasisInfo.getCellData(0, field);
        d[field] = val ? $c.gus.cfGetFormatStr(val, "####/##/## ##:##") : "";
    });

    // 행 추가 헬퍼 함수
    var addRow = function (label1, value1, label2, value2, label3, value3) {
        var idx = gen_basicinfoList.insertChild();
        gen_basicinfoList.getChild(idx, "txt_label1").setValue(label1);
        gen_basicinfoList.getChild(idx, "txt_value1").setValue(value1);
        gen_basicinfoList.getChild(idx, "txt_label2").setValue(label2);
        gen_basicinfoList.getChild(idx, "txt_value2").setValue(value2);
        gen_basicinfoList.getChild(idx, "txt_label3").setValue(label3);
        gen_basicinfoList.getChild(idx, "txt_value3").setValue(value3);
    };

    gen_basicinfoList.removeAll();

    // 선명, LINE, 선사
    addRow("선명", d.vsslNm, "LINE", d.lineNm, "선사", d.shpCoNm);

    // 수입/수출 항차 및 대표화종 (값이 있는 경우에만 행 추가)
    if (d.impPortcnt) addRow("항차", d.impPortcnt, "대표화종", d.impRepKcg, "수출입구분", "수입");
    if (d.expPortcnt) addRow("항차", d.expPortcnt, "대표화종", d.expRepKcg, "수출입구분", "수출");

    // 작업장, 입출항 일시
    addRow("작업장", d.wrkPlNm, "입항(예정)일시", d.arrvlportDtm, "출항(예정)일시", d.deprtportDtm);

    // 포맨 정보
    addRow("Chief 포맨", d.cfmanNm, "본선포맨", d.cvsslFmanCnt, "육상포맨", d.groundFmanCnt);
};

// 페이지 로드 시 기본 UI 구성 (데이터 없는 상태)
scwin.f_initDivHoldEachWorkPlanList = function () {
    gen_basicinfoList.removeAll();

    // 행 추가 헬퍼 함수
    var addRow = function (label1, value1, label2, value2, label3, value3) {
        var idx = gen_basicinfoList.insertChild();
        gen_basicinfoList.getChild(idx, "txt_label1").setValue(label1);
        gen_basicinfoList.getChild(idx, "txt_value1").setValue(value1);
        gen_basicinfoList.getChild(idx, "txt_label2").setValue(label2);
        gen_basicinfoList.getChild(idx, "txt_value2").setValue(value2);
        gen_basicinfoList.getChild(idx, "txt_label3").setValue(label3);
        gen_basicinfoList.getChild(idx, "txt_value3").setValue(value3);
    };

    // 기본 레이아웃 행 구성(빈 값으로 UI 유지)
    addRow("선명", "&nbsp;", "LINE", "&nbsp;", "선사", "&nbsp;");
    addRow("항차", "&nbsp;", "대표화종", "&nbsp;", "수출입구분", "&nbsp;");
    addRow("작업장", "&nbsp;", "입항(예정)일시", "&nbsp;", "출항(예정)일시", "&nbsp;");
    addRow("Chief 포맨", "&nbsp;", "본선포맨", "&nbsp;", "육상포맨", "&nbsp;");
};

//-------------------------------------------------------------------------
// 본선작업계획상세조회 테이블 생성
//------------------------------------------------------------------------- 
scwin.f_CarryingVesselCompletionInformation = function () {
    gen_completioninfoList.removeAll();

    var addRow = function (impExpClsNm, workCompleteYn, workCompleteDt) {
        var idx = gen_completioninfoList.insertChild();
        gen_completioninfoList.getChild(idx, "txt_impExpClsNm").setValue(impExpClsNm);
        gen_completioninfoList.getChild(idx, "txt_workCompleteYn").setValue(workCompleteYn);
        gen_completioninfoList.getChild(idx, "txt_workCompleteDt").setValue(workCompleteDt);
    };

    if (ds_carryingVesselCompletionInformation.getRowCount() > 0) {
        ds_carryingVesselCompletionInformation.getAllJSON().forEach(function (item) {
            addRow(
                item.impExpClsNm,
                item.cvsslWrkCompleteYn === "1" ? "Yes" : "No",
                item.cvsslWrkCompleteDt
            );
        });
    } else {
        scwin.f_initCarryingVesselCompletionInformation();
    }
};

// 페이지 로드 시 기본 UI 구성 (데이터 없는 상태)
scwin.f_initCarryingVesselCompletionInformation = function () {
    gen_completioninfoList.removeAll();

    var idx = gen_completioninfoList.insertChild();
    gen_completioninfoList.getChild(idx, "txt_impExpClsNm").setValue("&nbsp;");
    gen_completioninfoList.getChild(idx, "txt_workCompleteYn").setValue("&nbsp;");
    gen_completioninfoList.getChild(idx, "txt_workCompleteDt").setValue("");
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    ed_cvsslMgntNo.setValue("");
    ed_cvsslMgntNo.focus();
};

//-------------------------------------------------------------------------
// SHIFTING매출생성  엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_shiftingExcel = function () {
    $c.data.downloadGridViewExcel(gr_cargoShiftingResults, { fileName: "Shifting매출.xlsx", sheetName: "Shifting매출" }, 4 + 8 + 16);
};

//-------------------------------------------------------------------------
// 행추가 
//-------------------------------------------------------------------------
scwin.f_AddRowShift = function () {
    scwin.flagAddRow = true;

    let curRow = ds_cargoShiftingResults.insertRow();
    gr_cargoShiftingResults.setFocusedCell(curRow, "impExpClsNm");

    let prevRow = curRow - 1;

    if (prevRow >= 0) {
        ds_cargoShiftingResults.setCellData(curRow, "odrNo", ds_cargoShiftingResults.getCellData(prevRow, "odrNo"));
        ds_cargoShiftingResults.setCellData(curRow, "cvsslMgntNo", ds_cargoShiftingResults.getCellData(prevRow, "cvsslMgntNo"));
        ds_cargoShiftingResults.setCellData(curRow, "impExpClsNm", ds_cargoShiftingResults.getCellData(prevRow, "impExpClsNm"));
        ds_cargoShiftingResults.setCellData(curRow, "impExpClsCd", ds_cargoShiftingResults.getCellData(prevRow, "impExpClsCd"));
        ds_cargoShiftingResults.setCellData(curRow, "selpchItemNm", ds_cargoShiftingResults.getCellData(prevRow, "selpchItemNm"));
        ds_cargoShiftingResults.setCellData(curRow, "selpchItemCd", ds_cargoShiftingResults.getCellData(prevRow, "selpchItemCd"));
        ds_cargoShiftingResults.setCellData(curRow, "commNm", ds_cargoShiftingResults.getCellData(prevRow, "commNm"));
        ds_cargoShiftingResults.setCellData(curRow, "commCd", ds_cargoShiftingResults.getCellData(prevRow, "commCd"));
        ds_cargoShiftingResults.setCellData(curRow, "wrkStpNm", ds_cargoShiftingResults.getCellData(prevRow, "wrkStpNm"));
        ds_cargoShiftingResults.setCellData(curRow, "wrkStpCd", ds_cargoShiftingResults.getCellData(prevRow, "wrkStpCd"));
        ds_cargoShiftingResults.setCellData(curRow, "cntrSizCd", ds_cargoShiftingResults.getCellData(prevRow, "cntrSizCd"));
        ds_cargoShiftingResults.setCellData(curRow, "ctrtNo", ds_cargoShiftingResults.getCellData(prevRow, "ctrtNo"));
        ds_cargoShiftingResults.setCellData(curRow, "berthCd", ds_cargoShiftingResults.getCellData(prevRow, "berthCd"));
    }
    ds_cargoShiftingResults.setCellData(curRow, "sellClsCd", "N");

    ds_cargoShiftingResults.setCellData(curRow, "adptQty", "0");
    ds_cargoShiftingResults.setCellData(curRow, "adptWt", "0");
    ds_cargoShiftingResults.setCellData(curRow, "adptCbm", "0");
    ds_cargoShiftingResults.setCellData(curRow, "ctrtTrf", "0");
    ds_cargoShiftingResults.setCellData(curRow, "sellAmtFcrc", "0");
    ds_cargoShiftingResults.setCellData(curRow, "sellAmt", "0");
    ds_cargoShiftingResults.setCellData(curRow, "sellCtrlAmtFcrc", "0");
    ds_cargoShiftingResults.setCellData(curRow, "sellCtrlAmt", "0");



};

//-------------------------------------------------------------------------
// 행삭제 
//-------------------------------------------------------------------------
scwin.f_DeleteRowShift = function () {
    let curRow = ds_cargoShiftingResults.getRowPosition();
    if (curRow < 0) return;

    // 이미 삭제된 행이면 무시
    if (ds_cargoShiftingResults.getRowStatus(curRow) === "D") return;

    if (ds_cargoShiftingResults.getCellData(curRow, "cargoShiftingRsltsSeq") == 0) {
        ds_cargoShiftingResults.removeRow(curRow);
    } else {
        ds_cargoShiftingResults.deleteRow(curRow);
    }
};

//-------------------------------------------------------------------------
// 금액 반올림
//-------------------------------------------------------------------------
scwin.f_Round = function (Num, Position, Base) {
    // Num = 반올림할 수
    // Position = 반올림할 자릿수(정수로만)
    // Base = i 이면 소숫점위의 자릿수에서, f 이면 소숫점아래의 자릿수에서 반올림

    if (Position == 0) {
        return Math.round(Num);
    } else if (Position > 0) {
        let cipher = '1';
        for (let i = 0; i < Position; i++)
            cipher = cipher + '0';

        let no = Number(cipher);

        if (Base == "F") {
            // 소숫점아래에서 반올림
            return Math.round(Num * no) / no;
        } else {
            // 소숫점위에서 반올림.
            return Math.round(Num / no) * no;
        }
    } else {
        $c.win.alert("자릿수는 정수로만 구분합니다.");
        return false;
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let count = 0;
    let count1 = 0;
    let chg = 0;
    let hodrNo = "";
    let delcount = 0;

    for (let i = 0; i < ds_caculateShiftingSellingHidden1.getRowCount(); i++) {
        for (let j = 0; j < ds_cargoShiftingResults.getRowCount(); j++) {
            if (ds_cargoShiftingResults.getCellData(j, "chk") === "1") {
                if (ds_cargoShiftingResults.getCellData(j, "adptQty") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptQty")
                    || ds_cargoShiftingResults.getCellData(j, "adptWt") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptWt")
                    || ds_cargoShiftingResults.getCellData(j, "adptCbm") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptCbm")
                    || ds_cargoShiftingResults.getCellData(j, "sellAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmtFcrc")
                    || ds_cargoShiftingResults.getCellData(j, "sellAmt") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmt")
                    || ds_cargoShiftingResults.getCellData(j, "sellCtrlAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellCtrlAmtFcrc")) {
                    ds_cargoShiftingResults.setCellData(j, "commNm", ds_caculateShiftingSellingHidden1.getCellData(i, "commNm") + " ");
                    chg++;
                }
            }
        }
    }

    if (!(await $c.gus.cfValidate([gr_cargoShiftingResults], null, true))) {
        return;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "1" && ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매출항목"]);
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "1") {
            count++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
            count1++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "C" && scwin.count2 == 0) {
            scwin.count3++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1") {
            if (ds_cargoShiftingResults.getCellData(i, "ctrtTrf") == 0) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 데이터의 계약요율이 존재하지 않으므로 " + (i + 1) + "번째 데이터는 저장할수가 없습니다.");
                ds_cargoShiftingResults.setCellData(i, "chk", "0");
                scwin.count3 = 0;
                scwin.count2++;
                return false;
            }
        }
    }

    if (chg == 0 && scwin.count3 == 0 && count1 == 0) {
        for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
            if (ds_cargoShiftingResults.getCellData(i, "chk") === "0") {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
                return false;
            } else {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["SHIFTING 매출"]);
                return false;
            }
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1" && ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
            if (ds_cargoShiftingResults.getRowStatus(i) !== "C") {
                ds_cargoShiftingResults.modifyRowStatus(i, "U"); // 기존 행 → UPDATE
            }
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1"
            && ds_cargoShiftingResults.getCellData(i, "adptQty") == 0 && ds_cargoShiftingResults.getCellData(i, "adptWt") == 0
            && ds_cargoShiftingResults.getCellData(i, "adptCbm") == 0
            && ds_cargoShiftingResults.getCellData(i, "sellCtrlAmtFcrc") == 0) {
            await $c.win.alert((i + 1) + "번째 데이터는 변경된 사항이 없습니다. 선택된 체크박스를 해제해 주십시오.");
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
            delcount = delcount + 1;
        }
    }

    if (count == 0 && count1 == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
        return false;
    } else {
        if (delcount != ds_cargoShiftingResults.getRowCount()) {
            let chk = await $c.win.confirm("선택된 데이터만 저장이 가능합니다.저장하시겠습니까?");
            if (chk) {
                await $c.sbm.execute(sbm_save);
            }
        } else {
            let chk = await $c.win.confirm("저장하시겠습니까?");
            if (chk) {
                await $c.sbm.execute(sbm_save);
            }
        }
    }
};

//-------------------------------------------------------------------------
// shifting 매출 계산 
//-------------------------------------------------------------------------
scwin.f_Caculate = async function () {
    let count = 0;
    // 필수항목 체크
    if (!(await $c.gus.cfValidate([ed_cvsslMgntNo]))) {
        return;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1" && ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매출항목"]);
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1") {
            count++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (count == 0 && ds_cargoShiftingResults.getRowStatus(i) == "D") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["행삭제를 한 데이터", "SHIFTING 매출 계산을"]);
            return false;
        }
    }

    if (count == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["SHIFTING 매출을 계산할 매출항목"]);
        return false;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1" && ds_cargoShiftingResults.getCellData(i, "adptQty") == 0
            && ds_cargoShiftingResults.getCellData(i, "adptWt") == 0 && ds_cargoShiftingResults.getCellData(i, "adptCbm") == 0) {
            await $c.gus.cfAlertMsg("수량 혹은 중량 중 하나는 0보다 큰 값으로 입력하십시오.");
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1") {
            ds_cargoShiftingResults.setCellData(i, "commNm", ds_cargoShiftingResults.getCellData(i, "commNm") + " ");
        }
    }

    ds_caculateShiftingSellingHidden.removeAll();
    ds_caculateShiftingSellingHidden2.removeAll();

    ds_caculateShiftingSelling.setJSON([]);

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") === "1" && ds_cargoShiftingResults.getRowStatus(i) != "D") {
            ds_caculateShiftingSellingHidden2.removeAll();

            // 2. 새 row 추가 후 컬럼별 값 복사
            // let newRow = ds_caculateShiftingSellingHidden2.insertRow();
            // ds_caculateShiftingSellingHidden2.setRowJSON(newRow, ds_cargoShiftingResults.getRowJSON(i));
            ds_caculateShiftingSellingHidden2.setJSON([ds_cargoShiftingResults.getRowJSON(i)]);
            ds_caculateShiftingSellingHidden2.modifyAllStatus("C");

            await $c.sbm.execute(sbm_caculate);
            await scwin.f_Caculate1(i);
        }
    }
};

scwin.f_Caculate1 = async function (row) {

    // 1. 데이터가 아예 없는지 먼저 확인
    if (ds_caculateShiftingSelling.getRowCount() === 0) {
        await $c.gus.cfAlertMsg((row + 1) + "번째 데이터의 계약요율이 없습니다.");
        return false;
    }

    if (ds_caculateShiftingSelling.getCellData(0, "crcCd") == "") {
        await $c.gus.cfAlertMsg((row + 1) + "번째 데이터의 계약요율이 없습니다.");
        return false;
    }

    // row 0 복사: ds_caculateShiftingSelling → ds_caculateShiftingSelling_1
    ds_caculateShiftingSelling_1.setJSON(ds_caculateShiftingSelling.getAllJSON());

    // row 0 복사: ds_caculateShiftingSelling_1 → ds_caculateShiftingSelling (역방향)
    ds_caculateShiftingSelling.setJSON(ds_caculateShiftingSelling_1.getAllJSON());
    ds_caculateShiftingSelling.setCellData(0, "stdDt",
        ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));

    await $c.sbm.execute(sbm_ExchRate);
    let stdExchRt = ds_ExchRate.getRowCount() > 0 ? ds_ExchRate.getCellData(0, "stdExchRt") : "0";
    ds_cargoShiftingResults.setCellData(row, "stdExchRt", stdExchRt);

    if (ds_caculateShiftingSelling.getCellData(0, "crcCd") == "KRW") {
        if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "01") { // 상위단위코드가 수량이면 
            ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptQty") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
        }
        else if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "02") { // 상위단위코드가 중량이면  
            if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "KG") {
                ds_cargoShiftingResults.setCellData(row, "sellAmt", (ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf")) * 1000);
            } else {
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
            }
        }
        else if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "04") { // 상위단위코드가 용적이면 
            if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "R/T") {
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > ds_cargoShiftingResults.getCellData(row, "adptCbm")) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptCbm") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
                }
            } else if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "RNT") {
                let v_Cbm = scwin.f_Round((ds_cargoShiftingResults.getCellData(row, "adptCbm") / 1.133), 3, 'F');
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > v_Cbm) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", v_Cbm * ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
                }
            }
        }
        ds_cargoShiftingResults.setCellData(row, "ctrtTrf", ds_caculateShiftingSelling.getCellData(0, "ctrtTrf"));
        ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", 0);
        ds_cargoShiftingResults.setCellData(row, "sellCtrlAmtFcrc", 0);
    } else {
        if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "01") { // 상위단위코드가 수량이면 
            ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptQty") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
            ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
        }
        else if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "02") {  // 상위단위코드가 중량이면 
            if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "KG") {
                ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc") * 1000);
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt") * 1000);
            } else {
                ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
            }
        }
        else if (ds_caculateShiftingSelling.getCellData(0, "unitClsCd") == "04") { // 상위단위코드가 용적이면
            if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "R/T") {
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > ds_cargoShiftingResults.getCellData(row, "adptCbm")) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptCbm") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                }
            } else if (ds_caculateShiftingSelling.getCellData(0, "unitCd") == "RNT") {
                let v_Cbm = scwin.f_Round((ds_cargoShiftingResults.getCellData(row, "adptCbm") / 1.133), 3, 'F');
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > v_Cbm) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", v_Cbm * ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                }
            }
        }

        if (ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") > 0) {
            ds_cargoShiftingResults.setCellData(row, "sellCtrlAmt", ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
        } else if (ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") == 0) {
            ds_cargoShiftingResults.setCellData(row, "sellCtrlAmt", 0);
        }
        ds_cargoShiftingResults.setCellData(row, "ctrtTrf", ds_caculateShiftingSelling.getCellData(0, "ctrtTrfFcrc"));
    }

    ds_cargoShiftingResults.setCellData(row, "crcCd", ds_caculateShiftingSelling.getCellData(0, "crcCd"));
    ds_cargoShiftingResults.setCellData(row, "unitCd", ds_caculateShiftingSelling.getCellData(0, "unitCd"));
    ds_cargoShiftingResults.setCellData(row, "unitNm", ds_caculateShiftingSelling.getCellData(0, "unitNm"));
    ds_cargoShiftingResults.setCellData(row, "ctrtNo", ds_caculateShiftingSelling.getCellData(0, "ctrtNo"));
    ds_cargoShiftingResults.setCellData(row, "unitClsCd", ds_caculateShiftingSelling.getCellData(0, "unitClsCd"));

    ds_cargoShiftingResults.setCellData(row, "commNm", ds_cargoShiftingResults.getCellData(row, "commNm") + " ");

    if (ds_cargoShiftingResults.getCellData(row, "crcCd") == "KRW") {
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", true);
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", false);
    } else {
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", false);
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", true);
    }
};

//-------------------------------------------------------------------------
// 본선관리번호검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function () {
    let args = new Array();
    args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
    args[1] = ''; //수출입구분코드

    let rtnValues = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", {
        title: "본선관리번호검색팝업",
        popupName: "본선관리번호검색화면",
        type: 'browserPopup',
        width: 1080,
        height: 650
    }, args);

    if (rtnValues != null) {
        ed_cvsslMgntNo.setValue(rtnValues[0]);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    var result = e.responseJSON?.resultDataSet?.[0];

    if (!result) return;
    if (result.Msg === "SUCC") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_RetrieveShiftingResults();
    }
};

scwin.sbm_condition_submitdone = async function (e) {
    var result = e.responseJSON?.resultDataSet?.[0];

    if (!result) return;
    if (result.Msg !== "SUCC") return;

    scwin.f_DivHoldEachWorkPlanList();

    // 본선기본정보 DataSet
    // GAUCE: ds_carryingVesselCompletionInformation event=OnLoadCompleted(rowCnt)
    scwin.f_CarryingVesselCompletionInformation();

    let rowCntCompletion = ds_carryingVesselCompletionInformation.getRowCount();
    let saveCheck = 0;
    for (let i = 0; i < rowCntCompletion; i++) {
        if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteYn") == "0") {
            saveCheck = saveCheck + 1;
        }
    }

    if (rowCntCompletion == saveCheck) {
        $c.gus.cfDisableBtn([btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);
        gr_cargoShiftingResults.setReadOnly("grid", true);
    } else {
        $c.gus.cfEnableObjects([btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);
        gr_cargoShiftingResults.setReadOnly("grid", false);
    }

    for (let i = 0; i < rowCntCompletion; i++) {
        if (i + 1 < rowCntCompletion) {
            if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt") >= ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt")) {
                ds_carryingVesselCompletionInformation.setCellData(0, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt"));
                if (ds_carryingVesselCompletionInformation.getRowCount() > 1) {
                    ds_carryingVesselCompletionInformation.setCellData(1, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt"));
                }
            } else {
                ds_carryingVesselCompletionInformation.setCellData(0, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt"));
                if (ds_carryingVesselCompletionInformation.getRowCount() > 1) {
                    ds_carryingVesselCompletionInformation.setCellData(1, "cvsslWrkCompleteDt", ds_carryingVesselCompletionInformation.getCellData(i + 1, "cvsslWrkCompleteDt"));
                }
            }
        }
    }

    let rowCntShifting = ds_ShiftingResults.getRowCount();
    totalRows1.setValue(rowCntShifting);

    // 본선기본정보 DataSet
    // ds_cargoShiftingResults >> onLoadComplete(rowCnt)
    let rowCntCargo = ds_cargoShiftingResults.getRowCount();
    totalRows2.setValue(rowCntCargo);

    scwin.imptotal = 0;
    scwin.exptotal = 0;

    if (rowCntCargo == 0 && rowCntShifting == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        $c.gus.cfDisableBtn([btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]); // 본선미완료시 매출생성 못함
        gr_cargoShiftingResults.setReadOnly("grid", true);
        return false;
    }

    // OUT_DS4
    if (rowCntShifting > 0) {
        if (rowCntCargo == 0) {
            ds_cargoShiftingResults.setJSON(ds_ShiftingResults.getAllJSON());
            for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
                ds_cargoShiftingResults.setCellData(i, "adptQty", ds_ShiftingResults.getCellData(i, "rsltsQty"));
                ds_cargoShiftingResults.setCellData(i, "adptWt", ds_ShiftingResults.getCellData(i, "rsltsWt"));
                ds_cargoShiftingResults.setCellData(i, "adptCbm", ds_ShiftingResults.getCellData(i, "rsltsCbm"));

                if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "I") {
                    scwin.imptotal = scwin.imptotal + 1;
                } else if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "O") {
                    scwin.exptotal = scwin.exptotal + 1;
                }
            }
            for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
                ds_cargoShiftingResults.setCellData(i, "impTotal", scwin.imptotal);
                ds_cargoShiftingResults.setCellData(i, "expTotal", scwin.exptotal);
            }
        } else {
            for (let i = 0; i < rowCntShifting; i++) {
                let check = 0;
                for (let j = 0; j < ds_cargoShiftingResults.getRowCount(); j++) {
                    if (ds_ShiftingResults.getCellData(i, "impExpClsCd") == ds_cargoShiftingResults.getCellData(j, "impExpClsCd")
                        && ds_ShiftingResults.getCellData(i, "commCd") == ds_cargoShiftingResults.getCellData(j, "commCd")
                        && ds_ShiftingResults.getCellData(i, "wrkStpCd") == ds_cargoShiftingResults.getCellData(j, "wrkStpCd")) {
                        check++;
                    }
                }
                if (check == 0) {
                    let importRow = ds_cargoShiftingResults.insertRow();

                    ds_cargoShiftingResults.setRowJSON(importRow, ds_ShiftingResults.getRowJSON(i));
                    ds_cargoShiftingResults.setCellData(importRow, "adptQty", ds_ShiftingResults.getCellData(i, "rsltsQty"));
                    ds_cargoShiftingResults.setCellData(importRow, "adptWt", ds_ShiftingResults.getCellData(i, "rsltsWt"));
                    ds_cargoShiftingResults.setCellData(importRow, "adptCbm", ds_ShiftingResults.getCellData(i, "rsltsCbm"));
                }
            }
        }

        for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
            if (ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
                let wrkStpCd = ds_cargoShiftingResults.getCellData(i, "wrkStpCd");
                if (wrkStpCd == "0007") {
                    if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
                        scwin.clsCd = 1;

                        scwin.filterSelpchItemCd(wrkStpCd);
                        ds_cargoShiftingResults.setCellData(i, "selpchItemCd", ds_sellingItem.getCellData(0, "sellItemCd"));
                    }
                } else if (wrkStpCd == "0008") {
                    if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
                        scwin.clsCd = 2;
                        // ds_sellingItem 필터는 해당 cell 수정 시에 적용
                        scwin.filterSelpchItemCd(wrkStpCd);

                        ds_cargoShiftingResults.setCellData(i, "selpchItemCd", ds_sellingItem.getCellData(0, "sellItemCd"));
                    }
                }

                ds_sellingItem.clearFilter();
            }
        }
    }

    // OUT_DS2
    if (rowCntCargo > 0) {
        for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
            if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "I") {
                scwin.imptotal = scwin.imptotal + 1;
            } else if (ds_cargoShiftingResults.getCellData(i, "impExpClsCd") == "O") {
                scwin.exptotal = scwin.exptotal + 1;
            }
        }
        for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
            ds_cargoShiftingResults.setCellData(i, "impTotal", scwin.imptotal);
            ds_cargoShiftingResults.setCellData(i, "expTotal", scwin.exptotal);
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        dma_conditionContract.set("cvsslMgntNo", ds_cargoShiftingResults.getCellData(i, "cvsslMgntNo"));
        dma_conditionContract.set("wrkStpCd", ds_cargoShiftingResults.getCellData(i, "wrkStpCd"));
        dma_conditionContract.set("odrKndCd", ds_cargoShiftingResults.getCellData(i, "odrKndCd"));

        ds_ctrtNo.removeAll();

        await $c.sbm.execute(sbm_contractInformation);

        if (ds_ctrtNo.getRowCount() == 0) {
            $c.gus.cfAlertMsg("해당 본선의 계약번호가 없습니다.");

        } else {
            var cargoCrtNo = ds_cargoShiftingResults.getCellData(i, "ctrtNo");

            var matchIdx = scwin.findRowByValue(ds_ctrtNo, "ctrtNo", cargoCrtNo);

            if (matchIdx > -1) {
                ds_cargoShiftingResults.setCellData(
                    i,
                    "ctrtNoDetail",
                    ds_ctrtNo.getCellData(matchIdx, "ctrtNoDetail")
                );
            }

            var options = {};
            options.sortIndex = "ctrtNo ctrtWrkPathNm taxnClsCd";
            options.sortOrder = "-1 1 -1"; // 내림차순 (DESC): -1, 오름차순 (ASC): 1

            ds_ctrtNo.multisort(options);

            if (ds_cargoShiftingResults.getCellData(i, "sellClsCd") === "N") {
                ds_cargoShiftingResults.setCellData(i, "ctrtNo", ds_ctrtNo.getCellData(0, "ctrtNo"));
                ds_cargoShiftingResults.setCellData(i, "ctrtNoDetail", ds_ctrtNo.getCellData(0, "ctrtNoDetail"));
                ds_cargoShiftingResults.setCellData(i, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(0, "ctrtWrkPathSeq"));
                ds_cargoShiftingResults.setCellData(i, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(0, "ctrtWrkStpSeq"));
                ds_cargoShiftingResults.setCellData(i, "taxnClsCd", ds_ctrtNo.getCellData(0, "taxnClsCd"));
                ds_cargoShiftingResults.setCellData(i, "berthCd", ds_ctrtNo.getCellData(0, "berthCd"));
            }
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        ds_caculateShiftingSelling.setJSON([{
            "crcCd": ds_cargoShiftingResults.getCellData(i, "crcCd"),
            "stdDt": ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt") ?? ""
        }]);

        await $c.sbm.execute(sbm_ExchRate);
        let stdExchRt = ds_ExchRate.getRowCount() > 0 ? ds_ExchRate.getCellData(0, "stdExchRt") : "0";
        ds_cargoShiftingResults.setCellData(i, "stdExchRt", stdExchRt);
    }

    //ds_cargoShiftingResults.modifyAllStatus("R"); // 모든 행을 초기 상태로 변경
    ds_cargoShiftingResults.reform();

    ds_caculateShiftingSellingHidden1.removeAll();
    ds_caculateShiftingSellingHidden1.setJSON(ds_cargoShiftingResults.getAllJSON());
};

scwin.findRowByValue = function(ds, colId, value) {

    for (var i = 0; i < ds.getRowCount(); i++) {
        if (ds.getCellData(i, colId) == value) {
            return i;
        }
    }
    return -1;
}

// SHIFTING매출 그리드  체크박스 클릭시 (gr_cargoShiftingResults OnClick)
scwin.gr_cargoShiftingResults_oncellclick = async function (rowIndex, columnIndex, columnId) {
    if (columnId !== "chk") return;

    if (ds_cargoShiftingResults.getCellData(rowIndex, "chk") === "1") {
        let impExpClsCd = ds_cargoShiftingResults.getCellData(rowIndex, "impExpClsCd");
        let targetClsCd = (impExpClsCd === "I") ? "I" : "O";
        let msgPrefix = (impExpClsCd === "I") ? "수입" : "수출";

        let rowCnt = ds_carryingVesselCompletionInformation.getRowCount();
        for (let i = 0; i < rowCnt; i++) {
            if (ds_carryingVesselCompletionInformation.getCellData(i, "impExpClsCd") === targetClsCd) {
                if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteYn") == "0") {  // 본선미완료이면
                    await $c.gus.cfAlertMsg(msgPrefix + "본선은 완료가 되지 않아 SHIFTING매출을 생성 하실수가 없습니다.");
                    ds_cargoShiftingResults.setCellData(rowIndex, "chk", "0");
                    $c.gus.cfDisableBtnOnly([btn_AddShift, btn_DeleteShift]);
                    return;
                } else {
                    ds_cargoShiftingResults.setCellData(rowIndex, "chk", "1");
                    $c.gus.cfEnableBtnOnly([btn_AddShift, btn_DeleteShift]);
                }
            }
        }
    }
};
// 행추가시 계약번호 알림 alert는 미표시
scwin.flagAddRow = false;

scwin.gr_cargoShiftingResults_onrowindexchange = async function (rowIndex, oldRow) {
    if (rowIndex < 0) return;

    let crcCd = ds_cargoShiftingResults.getCellData(rowIndex, "crcCd");
    if (crcCd === "KRW") {
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", true);
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", false);
    } else {
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmtFcrc", false);
        gr_cargoShiftingResults.setReadOnly("column", "sellCtrlAmt", true);
    }

    // GAUS와 동일하게 sellClsCd=="N" 인 경우만 계약번호 조회
    if (ds_cargoShiftingResults.getCellData(rowIndex, "sellClsCd") === "N") {
        dma_conditionContract.set("cvsslMgntNo", ds_cargoShiftingResults.getCellData(rowIndex, "cvsslMgntNo"));
        dma_conditionContract.set("wrkStpCd", ds_cargoShiftingResults.getCellData(rowIndex, "wrkStpCd"));
        dma_conditionContract.set("odrKndCd", ds_cargoShiftingResults.getCellData(rowIndex, "odrKndCd"));

        ds_ctrtNo.removeAll();

        await $c.sbm.execute(sbm_contractInformation);

        if (ds_ctrtNo.getRowCount() == 0) {
             $c.gus.cfAlertMsg("해당 본선의 계약번호가 없습니다.");
            // if (scwin.flagAddRow) {
            //     scwin.flagAddRow = false;
            // } else {
            //     $c.gus.cfAlertMsg("해당 본선의 계약번호가 없습니다.");
            // }
        } else {
            var options = {};
            options.sortIndex = "ctrtNo ctrtWrkPathNm taxnClsCd";
            options.sortOrder = "-1 1 -1"; // 내림차순 (DESC): -1, 오름차순 (ASC): 1
            ds_ctrtNo.multisort(options);

            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNo", ds_ctrtNo.getCellData(0, "ctrtNo"));
            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNoDetail", ds_ctrtNo.getCellData(0, "ctrtNoDetail"));
            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(0, "ctrtWrkPathSeq"));
            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(0, "ctrtWrkStpSeq"));
            ds_cargoShiftingResults.setCellData(rowIndex, "taxnClsCd", ds_ctrtNo.getCellData(0, "taxnClsCd"));
            ds_cargoShiftingResults.setCellData(rowIndex, "berthCd", ds_ctrtNo.getCellData(0, "berthCd"));

            gr_cargoShiftingResults.refreshCell(rowIndex, "ctrtNoDetail");
        }
    }

    // gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", { inputType: "text" });
};

scwin.gr_cargoShiftingResults_onviewchange = async function (info) {
    // 예시: {"oldValue":"","newValue":"101","rowIndex":1,"colIndex":0,"colId":"wrkPlCd"}
    let rowIndex = info.rowIndex;
    let colid = info.colId;

    let oldValue = info.oldValue;
    let newValue = info.newValue;

    switch (colid) {
        case "ctrtNoDetail":
            if (oldValue === newValue) break;

            ds_cargoShiftingResults.setCellData(rowIndex, "sellAmt", 0);
            ds_cargoShiftingResults.setCellData(rowIndex, "sellAmtFcrc", 0);
            ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", 0);
            ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtTrf", 0);
            ds_cargoShiftingResults.setCellData(rowIndex, "crcCd", "");
            ds_cargoShiftingResults.setCellData(rowIndex, "unitNm", "");

            let ctrtNorow = ds_ctrtNo.getMatchedIndex("ctrtNoDetail", newValue);

            if (ctrtNorow.length > 0) {
                ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNo", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtNo"));
                ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkPathSeq", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtWrkPathSeq"));
                ds_cargoShiftingResults.setCellData(rowIndex, "ctrtWrkStpSeq", ds_ctrtNo.getCellData(ctrtNorow[0], "ctrtWrkStpSeq"));
                ds_cargoShiftingResults.setCellData(rowIndex, "taxnClsCd", ds_ctrtNo.getCellData(ctrtNorow[0], "taxnClsCd"));
                ds_cargoShiftingResults.setCellData(rowIndex, "berthCd", ds_ctrtNo.getCellData(ctrtNorow[0], "berthCd"));
            }
            break;

        case "sellCtrlAmtFcrc":
            if (oldValue === newValue) return;

            if (newValue > 0) {
                let crcCd = ds_cargoShiftingResults.getCellData(rowIndex, "crcCd");
                if (crcCd !== "") {
                    if (crcCd === "KRW") {
                        ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", newValue);
                    } else {
                        ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt",
                            newValue * ds_cargoShiftingResults.getCellData(rowIndex, "stdExchRt"));
                    }
                }
            } else if (newValue == 0) {
                ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmt", 0);
            }

            if (newValue < 0) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_007, ["매출조정금액외화"]);
                ds_cargoShiftingResults.setCellData(rowIndex, colid, oldValue);
                return false;
            }

            break;

        case "sellCtrlAmt":
            if (oldValue === newValue) return;

            if (newValue > 0) {
                if (ds_cargoShiftingResults.getCellData(rowIndex, "crcCd") === "KRW") {
                    ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
                }
            } else if (newValue == 0) {
                ds_cargoShiftingResults.setCellData(rowIndex, "sellCtrlAmtFcrc", 0);
            }
            break;

        default:
            break;
    }
};

// 영대문자 변환 (본선관리번호)
scwin.applyUpper = function (value) {
    return value.toUpperCase();
}

// 소수점 3자리
scwin.fn_limitDecimal3 = function (value) {
    return scwin.fn_limitDecimal(value, 3);
};

// 계약번호 선택 formatter - choices 목록과 무관하게 값 그대로 표시
scwin.ctrtNoDetailFormatter = function (value) {
    return value || "";
};

// 소숫점 이하 자릿수 체크 + 천단위 콤마
// decimalLen : 소수점 자릿수 (기본값 3)
scwin.fn_limitDecimal = function (value, decimalLen) {
    if ($c.gus.cfIsNull(value)) return "";

    var len = decimalLen || 3;

    // 콤마 제거 후 처리
    var strValue = value.toString().replace(/,/g, "");
    var parts = strValue.split(".");

    var intPart = parts[0];

    // 소수점 이하 없으면 "0"을 len만큼 채움, 있으면 len자리로 자르고 부족하면 0으로 채움
    var decPart = parts.length > 1 ? parts[1].substring(0, len).padEnd(len, "0") : "0".repeat(len);

    // 천단위 콤마 적용
    var formatted = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",");

    return formatted + "." + decPart;
};


// 매출항목 필터
scwin.filterSelpchItemCd = function (wrkStpCd) {
    ds_sellingItem.clearFilter();

    // 2. wrkStpCd 값에 따른 필터 분기 처리
    if (wrkStpCd === "0007") {
        // [조건 1] wrkStpCd가 "0007"인 경우: 매출항목("sellItemCd")이 "0177"인 것만 표시
        ds_sellingItem.setColumnFilter({
            type: "row",
            colIndex: "sellItemCd",
            key: "0177",
            condition: 'and',  // 일치 조건
            exactMatch: true
        });

    } else {
        // [조건 2] wrkStpCd가 "0007"이 아닌 경우: 매출항목("sellItemCd")이 "0177"이 아닌 것만 표시
        ds_sellingItem.setColumnFilter({
            type: 'func',
            colIndex: "sellItemCd",
            key: fn_fi0177NotFilter,
            condition: "and"
        });
    }
}

// wrkStpCd가 "0007"이 아닌 경우: 매출항목("sellItemCd")이 "0177"이 아닌 것만 표시
var fn_fi0177NotFilter = function (cellData, tmpParam, rowIdx) {
    if (cellData.indexOf("0177") > -1) {
        return false;
    }
    return true;   // return이 true인 경우 적용하고 false인 경우 넘김
}

scwin.ctrtNoOri = "";

// 매출항목 필터링
scwin.gr_cargoShiftingResults_onbeforeedit = function (rowIndex, columnIndex, value) {
    let columnId = gr_cargoShiftingResults.getColumnID(columnIndex);
    if (columnId === "selpchItemCd") {
        let wrkStpCd = ds_cargoShiftingResults.getCellData(rowIndex, "wrkStpCd");
        if (wrkStpCd === "0007") {
            scwin.clsCd = 1;
        } else {
            scwin.clsCd = 2;
        }

        scwin.filterSelpchItemCd(wrkStpCd);
    }
    else if (columnId === "ctrtNoDetail") {
        if (ds_ctrtNo.getTotalRow() == 0) {
            scwin.ctrtNoOri = ds_cargoShiftingResults.getCellData(rowIndex, "ctrtNoDetail");
        }

        // onrowindexchange에서 이미 ds_ctrtNo 로드됨 → 이 시점에 select로 전환
        var info = {
            inputType: "select",
            options: {
                emptyItem: "true",
                allowNotInList: "true"
            },
            itemSet: {
                nodeset: "data:ds_ctrtNo",
                label: "ctrtNoDetail",
                value: "ctrtNoDetail"
            }
        }

        // 첫 번째 행, "a" 컬럼에 해당하는 셀의 inputType을 select로 변경
        gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", info);

    }
    return true;
};

scwin.gr_cargoShiftingResults_onafteredit = function (rowIndex, columnIndex, value) {
    let colid = gr_cargoShiftingResults.getColumnID(columnIndex);

    if (colid === "selpchItemCd") { // filter 초기화
        ds_sellingItem.clearFilter();
    }
    else if (colid === "adptWt" || colid === "adptCbm") {
        let defaultValue = (value == "" || value == null) ? "0.000" : value;
        ds_cargoShiftingResults.setCellData(rowIndex, colid, defaultValue);
    } 
    else if (colid === "ctrtNoDetail") {
        gr_cargoShiftingResults.setCellInputType(rowIndex, "ctrtNoDetail", {
            inputType: "text",
            emptyItem: "true"
        });

        // 계약번호 리스트 항목에 같은 값이 없으면 빈값처리되는 문제 해결을 위해 edit 전에 값 저장 후 셋팅
        if (value === "" && ds_ctrtNo.getTotalRow() == 0) {
            ds_cargoShiftingResults.setCellData(rowIndex, "ctrtNoDetail", scwin.ctrtNoOri);
        } 
    }
};
